/* Local Mermaid fallback shim for privacy-mode offline operation.
 * This is intentionally minimal and does not fetch remote assets.
 * If you want full Mermaid rendering, vendor the official mermaid.min.js
 * into this same local path.
 */
(function () {
  if (window.mermaid) return;

  function escapeHtml(input) {
    return String(input)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/\"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  window.mermaid = {
    initialize: function () {
      return;
    },
    render: function (_id, source) {
      var safe = escapeHtml(source || "");
      var svg = "<svg xmlns='http://www.w3.org/2000/svg' width='1200' height='240' viewBox='0 0 1200 240'>" +
        "<rect x='1' y='1' width='1198' height='238' fill='#0f172a' stroke='#334155' stroke-width='2' rx='8'/>" +
        "<text x='24' y='42' fill='#f8fafc' font-family='Segoe UI, sans-serif' font-size='16'>Mermaid offline placeholder</text>" +
        "<foreignObject x='20' y='58' width='1160' height='160'>" +
        "<div xmlns='http://www.w3.org/1999/xhtml' style='color:#94a3b8;font-family:Consolas,monospace;font-size:12px;white-space:pre-wrap;'>" + safe + "</div>" +
        "</foreignObject>" +
        "</svg>";
      return Promise.resolve({ svg: svg });
    }
  };
})();
